import { World, Body, Box, Sphere, Plane, Vec3, BODY_TYPES } from 'https://cdn.jsdelivr.net/npm/cannon-es@0.20.0/+esm';
const world = new World({ gravity: new Vec3(...(data.gravity ?? [0, -9.82, 0])) });
for (const b of data.bodies) {
  const s = b.shape.kind === 'sphere' ? new Sphere(b.shape.radius)
    : b.shape.kind === 'plane' ? new Plane()
    : new Box(new Vec3(...b.shape.halfExtents));
  const body = new Body({ mass: b.mass ?? 0, position: new Vec3(...b.position), shape: s, type: b.type === 'static' ? BODY_TYPES.STATIC : b.type === 'kinematic' ? BODY_TYPES.KINEMATIC : BODY_TYPES.DYNAMIC });
  world.addBody(body);
}
// 每帧:world.fixedStep(); 再把每个 body.position / body.quaternion 拷给对应 three.js mesh
